import{_ as r}from"./chunks/audio-player.81bc6281.js";import{_ as e,c as n,d as t,b as s,o as _}from"./app.aaa68922.js";const y='{"title":"\u041D\u0430\u043C\u0430\u0441\u0442\u0435 \u0430\u0441\u0442\u0443 \u0431\u0445\u0430\u0433\u0430\u0432\u0430\u043D","description":"","frontmatter":{"title":"\u041D\u0430\u043C\u0430\u0441\u0442\u0435 \u0430\u0441\u0442\u0443 \u0431\u0445\u0430\u0433\u0430\u0432\u0430\u043D","subtitle":"\u041F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0435 \u0412\u043B\u0430\u0434\u044B\u043A\u0435","sans":"\u0928\u092E\u0938\u094D\u0924\u0947 \u0905\u0938\u094D\u0924\u0941 \u092D\u0917\u0935\u0928\u094D","trans":"namaste astu bhagavan","tags":"mantra","date":"2021-04-25T00:00:00.000Z"},"headers":[],"relativePath":"mantra/namaste-astu/index.md"}',i={},o=s('<div class="stanza"><p class="sans">\u0928\u092E\u0938\u094D\u0924\u0947 \u0905\u0938\u094D\u0924\u0941 \u092D\u0917\u0935\u0928\u094D \u0964<br> \u0935\u093F\u0936\u094D\u0935\u0947\u0936\u094D\u0935\u0930\u093E\u092F \u092E\u0939\u093E\u0926\u0947\u0935\u093E\u092F \u0965<br> \u0924\u094D\u0930\u094D\u092F\u092E\u094D\u092C\u0915\u093E\u092F \u0924\u094D\u0930\u093F\u092A\u0941\u0930\u093E\u0928\u094D\u0924\u0915\u093E\u092F \u0964<br> \u0924\u094D\u0930\u093F\u0915\u093E\u0932\u093E\u0917\u094D\u0928\u093F\u0915\u093E\u0932\u093E\u092F \u0965<br> \u0915\u093E\u0932\u093E\u0917\u094D\u0928\u093F \u0930\u0941\u0926\u094D\u0930\u093E\u092F \u0964<br> \u0928\u093F\u0932\u0915\u0923\u094D\u0920\u093E\u092F \u092E\u0943\u0924\u094D\u092F\u0941\u0923\u094D\u091C\u092F\u093E\u092F \u0965<br> \u0938\u0930\u094D\u0935\u0947\u0936\u094D\u0935\u0930\u093E\u092F \u0938\u0926\u093E\u0936\u093F\u0935\u093E\u092F \u0964<br> \u0936\u094D\u0930\u0940\u092E\u0928\u094D\u092E\u0939\u093E\u0926\u0947\u0935\u093E\u092F \u0928\u092E\u0903 \u0965</p><p class="trans">namaste astu bhagavan \u0964<br> vi\u015Bve\u015Bvar\u0101ya mah\u0101dev\u0101ya \u0965<br> tryambak\u0101ya tripur\u0101ntak\u0101ya \u0964<br> trik\u0101l\u0101gnik\u0101l\u0101ya \u0965<br> k\u0101l\u0101gni rudr\u0101ya \u0964<br> nilaka\u1E47\u1E6Dh\u0101ya m\u1E5Btyu\u1E47jay\u0101ya \u0965<br> sarve\u015Bvar\u0101ya sad\u0101\u015Biv\u0101ya \u0964<br> \u015Br\u012Bmanmah\u0101dev\u0101ya nama\u1E25 \u0965</p><p>\u041F\u0440\u0438\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0435 \u0442\u0435\u0431\u0435, \u043E \u0411\u043E\u0433. \u0412\u043B\u0430\u0434\u044B\u043A\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0432\u0441\u0435\u0432\u044B\u0448\u043D\u0435\u043C\u0443 \u0411\u043E\u0433\u0443, \u0443 \u043A\u043E\u0433\u043E \u0442\u0440\u0438 \u0433\u043B\u0430\u0437\u0430, \u043A\u0442\u043E \u0441\u0436\u0435\u0433 \u0442\u0440\u0438 \u0434\u0435\u043C\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0433\u043E\u0440\u043E\u0434\u0430, \u043A\u0442\u043E \u2014 \u0442\u0440\u0438 \u043F\u0435\u0440\u0438\u043E\u0434\u0430 \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0435 \u043E\u0433\u043D\u044E, \u0440\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044E \u043E\u0433\u043D\u044F \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u0441\u0438\u043D\u0435\u0433\u043E\u0440\u043B\u043E\u043C\u0443, \u043F\u043E\u0431\u0435\u0434\u0438\u0442\u0435\u043B\u044E \u0441\u043C\u0435\u0440\u0442\u0438, \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044E \u0432\u0441\u0435\u0433\u043E, \u0432\u0435\u0447\u043D\u043E \u0431\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u043B\u0451\u043D\u043D\u043E\u043C\u0443, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u043C\u0443 \u0432\u0441\u0435\u043C \u0431\u043B\u0430\u0433\u043E\u043C \u0412\u0435\u043B\u0438\u043A\u043E\u043C\u0443 \u0411\u043E\u0433\u0443 \u043F\u043E\u043A\u043B\u043E\u043D.</p></div>',1);function m(p,c,d,l,u,h){const a=r;return _(),n("div",null,[o,t(a,{title:"Namaste astu Bhagavan",file:"/audio/Shiva_-_Namaste_astu_Bhagavan_oum_ru.mp3"}),t(a,{title:"Rattan Mohan Sharma - Shiva prathana",file:"/audio/Rattan_Mohan_Sharma_-_Shiva_Prarthana_oum_ru.mp3"})])}var f=e(i,[["render",m]]);export{y as __pageData,f as default};
